356→DEFINE FUNCTION fn::entity_search_workspace($q: string, $limit: int, $workspace: record<workspace>) {
357→  LET $query = string::lowercase(string::trim($q));
358→  LET $safe_limit = math::min([math::max([$limit, 1]), 100]);
359→
360→  LET $task_rows = SELECT
361→    id,
362→    "task" AS kind,
363→    title AS text,
364→    extraction_confidence AS confidence,
365→    source_message AS sourceMessage,
366→    priority,
367→    created_at
368→  FROM task
369→  WHERE workspace = $workspace
370→    AND extraction_confidence != NONE
371→    AND string::contains(string::lowercase(title), $query)
372→  ORDER BY created_at DESC
373→  LIMIT $safe_limit;
374→
375→  LET $decision_rows = SELECT
376→    id,
377→    "decision" AS kind,
378→    summary AS text,
379→    extraction_confidence AS confidence,
380→    source_message AS sourceMessage,
381→    priority,
382→    created_at
383→  FROM decision
384→  WHERE workspace = $workspace
385→    AND extraction_confidence != NONE
386→    AND string::contains(string::lowercase(summary), $query)
387→  ORDER BY created_at DESC
388→  LIMIT $safe_limit;
389→
390→  LET $question_rows = SELECT
391→    id,
392→    "question" AS kind,
393→    text AS text,
394→    extraction_confidence AS confidence,
395→    source_message AS sourceMessage,
396→    priority,
397→    created_at
398→  FROM question
399→  WHERE workspace = $workspace
400→    AND extraction_confidence != NONE
401→    AND string::contains(string::lowercase(text), $query)
402→  ORDER BY created_at DESC
403→  LIMIT $safe_limit;
404→
405→  RETURN array::flatten([$task_rows, $decision_rows, $question_rows]);
406→};
407→
408→DEFINE FUNCTION fn::entity_search_project($q: string, $limit: int, $workspace: record<workspace>, $project: record<project>) {
409→  LET $query = string::lowercase(string::trim($q));
410→  LET $safe_limit = math::min([math::max([$limit, 1]), 100]);
411→  LET $project_entity_ids = SELECT VALUE `in` FROM belongs_to WHERE out = $project;
412→
413→  LET $task_rows = SELECT
414→    id,
415→    "task" AS kind,
416→    title AS text,
417→    extraction_confidence AS confidence,
418→    source_message AS sourceMessage,
419→    priority,
420→    created_at
421→  FROM task
422→  WHERE workspace = $workspace
423→    AND extraction_confidence != NONE
424→    AND id IN $project_entity_ids
425→    AND string::contains(string::lowercase(title), $query)
426→  ORDER BY created_at DESC
427→  LIMIT $safe_limit;
428→
429→  LET $decision_rows = SELECT
430→    id,
431→    "decision" AS kind,
432→    summary AS text,
433→    extraction_confidence AS confidence,
434→    source_message AS sourceMessage,
435→    priority,
436→    created_at
437→  FROM decision
438→  WHERE workspace = $workspace
439→    AND extraction_confidence != NONE
440→    AND id IN $project_entity_ids
441→    AND string::contains(string::lowercase(summary), $query)
442→  ORDER BY created_at DESC
443→  LIMIT $safe_limit;
444→
445→  LET $question_rows = SELECT
446→    id,
447→    "question" AS kind,
448→    text AS text,
449→    extraction_confidence AS confidence,
450→    source_message AS sourceMessage,
451→    priority,
452→    created_at
453→  FROM question
454→  WHERE workspace = $workspace
455→    AND extraction_confidence != NONE
456→    AND id IN $project_entity_ids
457→    AND string::contains(string::lowercase(text), $query)
458→  ORDER BY created_at DESC
459→  LIMIT $safe_limit;
460→
461→  RETURN array::flatten([$task_rows, $decision_rows, $question_rows]);
462→};
463→
464→DEFINE FUNCTION fn::conversation_recent($conversation: record<conversation>, $limit: int) {
465→  LET $safe_limit = math::min([math::max([$limit, 1]), 50]);
466→  RETURN SELECT id, role, text, createdAt
467→  FROM message
468→  WHERE conversation = $conversation
469→  ORDER BY createdAt DESC
470→  LIMIT $safe_limit;
471→};
472→
473→DEFINE FUNCTION fn::entity_neighbors($entity: record) {
474→  RETURN SELECT
475→    ->entity_relation->(workspace, project, person, feature, task, decision, question) AS outgoing,
476→    <-entity_relation<-(workspace, project, person, feature, task, decision, question) AS incoming
477→  FROM $entity;
478→};
