                            }
                            let traceOrder = 0;
                            for (const trace of event.result.traces) {
                                traceOrder++;
                                await this.opts.storage.traces.create({
                                    resultId: resultId,
                                    input: trace.input,
                                    output: trace.output,
                                    start: trace.start,
                                    end: trace.end,
                                    inputTokens: trace.usage?.inputTokens,
                                    outputTokens: trace.usage?.outputTokens,
                                    totalTokens: trace.usage?.totalTokens,
                                    order: traceOrder,
                                });
