                        break;
                    default:
                        throw new Error(`${event.type} not allowed in ${this.state.type}`);
                }
            case "idle": {
                switch (event.type) {
                    case "RUN_BEGUN":
                        // Clear collected results for new run
                        this.collectedResults.clear();
                        this.updateState({
                            filepaths: event.filepaths,
                            runType: event.runType,
                            type: "running",
